2	 * Renders the Q&A transcript at the top of the page for stages that build
3	 * on it (questions / focus / processing / writing-style reveal / todos
4	 * reveal). Mounted once at the page level so the message list isn't
5	 * remounted on every stage transition. For pipeline stages, also nests
6	 * the `OnboardingProcessing` checklist inside the last bot bubble.
7	 */
8	
9	"use client";
10	
11	import { memo, useMemo } from "react";
12	import { hasGmail as hasGmailDerived } from "../state/derive";
13	import { getMessages } from "../state/messages";
14	import type { OnboardingState, Stage } from "../state/types";
15	import { OnboardingMessages } from "./OnboardingMessages";
16	import { OnboardingProcessing } from "./OnboardingProcessing";
17	
18	const STAGES_WITH_PROCESSING_CHECKLIST: ReadonlySet<Stage> = new Set<Stage>([
19	  "processing",
20	  "revealWriting",
21	  "revealTodos",
22	  "workflows",
23	  "platforms",
24	  "chat",
25	]);
26	
27	interface MessagesRegionProps {
28	  state: OnboardingState;
29	  stage: Stage;
30	}
31	
32	function MessagesRegionImpl({ state, stage }: MessagesRegionProps) {
33	  const messages = useMemo(
34	    () => getMessages(state),
35	    [
36	      state.responses,
37	      state.questionIndex,
38	      state.clarifyAnswers,
39	      state.clarifyQuestions,
40	      state.clarifySubmitted,
41	    ],
42	  );
43	
44	  const checklist = STAGES_WITH_PROCESSING_CHECKLIST.has(stage) ? (
45	    <OnboardingProcessing
46	      hasGmail={hasGmailDerived(state)}
47	      completedStages={state.completedStages}
48	      progressByStage={state.progressByStage}
49	    />
50	  ) : null;
51	
52	  return (
53	    <OnboardingMessages messages={messages} processingChecklist={checklist} />
54	  );
