2	import {
3	  splitByBreaksPreservingFences,
4	  splitMessageByBreaks,
5	} from "@shared/utils";
6	import * as m from "motion/react-m";
7	import Image from "next/image";
8	import { type ReactNode, useCallback, useMemo, useRef } from "react";
9	
10	import { SystemPurpose } from "@/features/chat/api/chatApi";
11	import ChatBubble_Actions from "@/features/chat/components/bubbles/actions/ChatBubble_Actions";
12	import ChatBubble_Actions_Image from "@/features/chat/components/bubbles/actions/ChatBubble_Actions_Image";
13	import MemoryIndicator from "@/features/chat/components/memory/MemoryIndicator";
14	import { useLoading } from "@/features/chat/hooks/useLoading";
15	import { shouldShowTextBubble } from "@/features/chat/utils/messageContentUtils";
16	import { parseThinkingFromText } from "@/features/chat/utils/thinkingParser";
17	import type { ChatBubbleBotProps } from "@/types/features/chatBubbleTypes";
18	import { parseDate } from "@/utils/date/dateUtils";
19	
20	import FollowUpActions from "./FollowUpActions";
21	import ImageBubble from "./ImageBubble";
22	import TextBubble, {
23	  MESSAGE_BREAK_DURATION_SECONDS,
24	  MESSAGE_BREAK_EASE_OUT_QUART,
25	  MESSAGE_BREAK_STAGGER_SECONDS,
26	} from "./TextBubble";
27	
28	export default function ChatBubbleBot(
29	  props: ChatBubbleBotProps & {
30	    disableActions?: boolean;
31	    hideAvatar?: boolean;
32	    children?: ReactNode;
33	  },
34	) {
35	  const {
36	    text,
37	    loading = false,
38	    message_id,
39	    pinned,
40	    image_data,
41	    date,
42	    memory_data,
43	    onOpenMemoryModal,
44	    isConvoSystemGenerated,
45	    systemPurpose,
46	    follow_up_actions,
47	    isLastMessage,
48	    disableActions = false,
49	    hideAvatar = false,
50	    children,
51	    onRetry,
52	    isRetrying,
53	  } = props;
54	  const { isLoading } = useLoading();
55	
56	  const actionsRef = useRef<HTMLDivElement>(null);
57	
58	  const handleMouseOver = useCallback(() => {
59	    if (actionsRef.current && !disableActions) {
60	      actionsRef.current.style.opacity = "1";
61	      actionsRef.current.style.visibility = "visible";
62	    }
63	  }, [disableActions]);
64	
65	  const handleMouseOut = useCallback(() => {
66	    if (actionsRef.current && !disableActions) {
67	      actionsRef.current.style.opacity = "0";
68	      actionsRef.current.style.visibility = "hidden";
69	    }
70	  }, [disableActions]);
71	
72	  const renderedComponent = useMemo(() => {
73	    if (image_data) return <ImageBubble {...props} image_data={image_data} />;
74	
75	    return <TextBubble {...props} />;
76	  }, [image_data, props]);
77	
78	  const itShouldShowTextBubble = shouldShowTextBubble(
79	    text,
80	    isConvoSystemGenerated,
81	    systemPurpose,
82	  );
83	
84	  const logoDelay = useMemo(() => {
85	    if (!itShouldShowTextBubble) return 0;
86	    const cleanText = parseThinkingFromText(text?.toString() || "").cleanText;
87	    if (!cleanText) return 0;
88	    const parts = cleanText.includes(":::openui")
89	      ? splitByBreaksPreservingFences(cleanText)
90	      : splitMessageByBreaks(cleanText);
91	    return Math.max(0, parts.length - 1) * MESSAGE_BREAK_STAGGER_SECONDS;
92	  }, [text, itShouldShowTextBubble]);
93	
94	  // Check if there's actual content to display
95	  const hasContent =
96	    image_data ||
97	    !!text ||
98	    (isConvoSystemGenerated &&
99	      systemPurpose === SystemPurpose.EMAIL_PROCESSING) ||
100	    props.tool_data?.length;
101	
102	  // Don't render the full bubble structure if only loading with no content
103	  // Let ChatRenderer's loading indicator handle it
104	  if (loading && !hasContent) return null;
105	
106	  const showBubbleChrome = itShouldShowTextBubble;
107	
108	  return (
109	    (loading || hasContent) && (
110	      <div
111	        id={message_id}
112	        onMouseOver={handleMouseOver}
113	        onMouseOut={handleMouseOut}
114	        className="relative flex flex-col"
115	        style={{ contentVisibility: "auto", containIntrinsicSize: "0 120px" }}
116	      >
117	        <div className="flex items-end gap-1">
118	          {!hideAvatar && (
119	            <div className="relative bottom-0 min-w-10 shrink-0">
120	              {showBubbleChrome && (
121	                <m.div
122	                  className={`${isLoading && isLastMessage ? "animate-spin" : ""} relative z-5 transition duration-900`}
123	                  initial={{ opacity: 0, scale: 0.8 }}
124	                  animate={{ opacity: 1, scale: 1 }}
125	                  transition={{
126	                    duration: MESSAGE_BREAK_DURATION_SECONDS,
127	                    ease: MESSAGE_BREAK_EASE_OUT_QUART,
128	                    delay: logoDelay,
129	                  }}
130	                >
131	                  <Image
132	                    alt="GAIA Logo"
133	                    src={"/images/logos/logo.webp"}
134	                    width={30}
135	                    height={30}
136	                  />
137	                </m.div>
138	              )}
139	            </div>
140	          )}
141	
142	          <div className="chatbubblebot_parent flex-1">
143	            <div className="flex w-full flex-col gap-2">
144	              {memory_data && onOpenMemoryModal && (
145	                <MemoryIndicator
146	                  memoryData={memory_data}
147	                  onOpenModal={onOpenMemoryModal}
148	                />
149	              )}
150	              <div className="chat_bubble_container">{renderedComponent}</div>
151	            </div>
152	          </div>
153	        </div>
154	
155	        {showBubbleChrome && (
156	          <div className="ml-10.75 flex flex-col">
157	            {!!follow_up_actions && follow_up_actions?.length > 0 && (
158	              <FollowUpActions
159	                actions={follow_up_actions}
160	                loading={!!loading}
161	              />
162	            )}
163	
164	            <div
165	              ref={actionsRef}
166	              className={`flex flex-col transition-all ${disableActions ? "hidden" : loading ? "opacity-0!" : "opacity-100"}`}
167	              style={{
168	                opacity: disableActions ? 1 : 0,
169	                visibility: disableActions ? "visible" : "hidden",
170	              }}
171	            >
172	              {date && !disableActions && (
173	                <span
